    if (pos == -1)
    {
        sb.append(newText);
        return sb;
    }

    // If findWrapPos returns 0, we need to force a break to avoid infinite loop
    // This happens when the text starts with characters that make it impossible to wrap
    if (pos == 0)
    {
        // Take at least one character to make progress
        pos = Math.max(1, Math.min(width, newText.length()));
    }

    // Check to prevent infinite loop - if position hasn't advanced meaningfully
    if (pos == lastPos && pos > 0 && newText.startsWith(text.substring(lastPos)))
    {
        // Force advancement by taking a chunk based on width
        pos = Math.max(pos + 1, Math.min(newText.length(), pos + width));
    }

    sb.append(rtrim(newText.substring(0, pos))).append(defaultNewLine);
    text = newText;
}

